INSERT INTO `recipes` VALUES (3,2,'Омлет с молоком','Пышный омлет с молоком на сковороде',15,'2026-04-20 12:54:23'),(4,2,'Борщ','Наваристый, густой, с ароматом копченостей.',120,'2026-04-20 14:44:09'),(5,3,'Паста фетучини с курицей','На скорую руку, необыкновенно вкусно и просто, на ужин!',20,'2026-04-20 15:22:21'),(6,3,'Салат','Самый бюджетный, простой и быстрый, на скорую руку!',20,'2026-04-20 15:27:36'),(7,4,'Стейк на мангале','Простой рецепт жареного на мангале мясного стейка.',120,'2026-04-20 15:33:07'),(8,4,'Блины с ветчиной и сыром','Вкусные, ароматные, с хрустящей корочкой!',35,'2026-04-20 15:39:03'),(9,5,'Тыквенный суп пюре','Ароматный, нежный, бархатистый.',20,'2026-04-20 15:45:29'),(10,5,'Плов в афганском казане','Неимоверно вкусный, ароматный, просто потрясающий!',50,'2026-04-20 15:50:45'),(11,6,'Овощное рагу с баклажанами','Вкусно, просто, легко, полезно, без мяса, на каждый день! Овощное рагу с баклажанами и кабачками подойдет вегетарианцам, соблюдающим пост, любителям низкокалорийных блюд.',90,'2026-04-20 16:08:55'),(12,6,'Кекс с яблоками в духовке','Аромат, от которого сбегутся все домочадцы!',120,'2026-04-20 16:14:03'),(13,7,'Компот из клубники','Яркий, освежающий, ароматный, с приятной кислинкой.',30,'2026-04-20 16:19:17'),(14,7,'Бамбл кофе','Взрыв вкуса — апельсин и кофе. Освежит в летнюю жару!',20,'2026-04-20 16:23:42'),(15,8,'Скумбрия в аэрогриле','Без хлопот, быстро и полезно - идеально для ужина!',80,'2026-04-20 16:32:31'),(16,8,'Морской окунь запечённый','Невероятно сочная и вкусная морская рыбка! Прекрасный вариант обеда или семейного ужина.',70,'2026-04-20 16:38:39'),(17,11,'Китайские пельмени','Необычные, колоритные. Никто не откажется попробовать!',50,'2026-04-21 05:42:51');
